p.m:
\displaystyle{\begin{aligned}
   2\div \frac{2}{3} 
       \amp = \frac{2}{1} \div \frac{2}{3} \\
       \amp = \frac{2}{1} \cdot \frac{3}{2} \amp \hbox{We can divide 2 and 2 by 2 and made those two values smaller.}\\
       \amp = \frac{1}{1}\cdot\frac{3}{1} \\
       \amp = \frac{1\cdot3}{1 \cdot 1} \\
       \amp = 3
\end{aligned}
    }
